# Shapes module - geometric shapes with cross-module inheritance

from types import Color, IDrawable, Point

@abstract
class Shape:
    color: Color
    position: Point

    def __init__(self, color: Color, position: Point):
        self.color = color
        self.position = position

    @abstract
    def area(self) -> float
    ...

    @abstract
    def perimeter(self) -> float
    ...

class Circle(Shape, IDrawable):
    radius: float

    def __init__(self, color: Color, position: Point, radius: float):
        super().__init__(color, position)
        self.radius = radius

    @override
    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def perimeter(self) -> float:
        return 2.0 * 3.14159 * self.radius

    @override
    def draw(self) -> str:
        return f"Circle at ({self.position.x}, {self.position.y})"

class Rectangle(Shape, IDrawable):
    width: float
    height: float

    def __init__(self, color: Color, position: Point, width: float, height: float):
        super().__init__(color, position)
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    @override
    def draw(self) -> str:
        return f"Rectangle at ({self.position.x}, {self.position.y})"

